import React from 'react'

const Head = () => {
    return (
        <header
            className="py-5 bg-image-full"
            style={{
                backgroundImage: 'url("assets/keyboard.jpg")'
            }}
            >
            <div className="text-center my-5">
                <img
                    className="img-fluid rounded-circle mb-4 photo img-thumbnail"
                    src={`/assets/pp.png`}
                    alt="..."
                />
                <h1 className="text-dark fs-3 fw-bolder">Elly Prasetyo</h1>
                <p className="text-dark-50 mb-0">Web Developer</p>
            </div>
        </header>
    )
}

export default Head
